// rt-find-contacts — Apollo /v1/mixed_people/search, output exact conform
// het find_contacts v1.0.0 output_schema uit rt_skill_versions.
// De Apollo Master API key komt uit de n8n-omgeving — NOOIT uit de payload.
const APOLLO_API_KEY = $env.APOLLO_API_KEY || '<APOLLO_API_KEY>';

const body = $input.first().json.body || $input.first().json;
const input = body.input || {};

if (!input.company_domain || !Array.isArray(input.roles) || input.roles.length === 0) {
  return [{ json: { error: { code: 'input_invalid', message: 'company_domain en roles zijn verplicht', retryable: false } } }];
}
const maxContacts = Math.min(Math.max(parseInt(input.max_contacts, 10) || 3, 1), 25);

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.apollo.io/v1/mixed_people/search',
    headers: {
      'X-Api-Key': APOLLO_API_KEY,
      'Content-Type': 'application/json',
      'Cache-Control': 'no-cache',
    },
    body: {
      q_organization_domains_list: [input.company_domain],
      person_titles: input.roles,
      per_page: maxContacts,
      page: 1,
    },
    json: true,
  });

  const people = response.people || response.contacts || [];
  const contacts = people
    .slice(0, maxContacts)
    .filter((p) => p.first_name && p.last_name)
    .map((p) => {
      // Apollo geeft 'email_not_unlocked@...' voor niet-onthulde adressen.
      const email = p.email && !String(p.email).includes('email_not_unlocked') ? p.email : null;
      return {
        first_name: p.first_name,
        last_name: p.last_name,
        title: p.title || '',
        email,
        email_status: p.email_status || null,
        linkedin_url: p.linkedin_url || null,
        phone: p.sanitized_phone || p.phone || null,
        source_provider: 'apollo',
        external_ids: { apollo_person_id: p.id },
      };
    });

  return [{ json: { contacts } }];
} catch (e) {
  const msg = String(e.message || e);
  const retryable = msg.includes('429') || msg.includes('50');
  return [{ json: { error: { code: 'apollo_error', message: msg.slice(0, 200), retryable } } }];
}
